 {"id":"bd-3ar8v.2.8.2","title":"[Phase 1][Support] Tighten phase1 matrix primary-outcome invariants in bench schema validation","description":"Strengthen phase1 matrix validation contract with deterministic numeric/type checks for wall_clock and Rust-vs-Node/Bun ratio outcomes, plus regression tests for malformed payloads so phase-1 evidence gates fail closed.","status":"in_progress","priority":0,"issue_type":"task","assignee":"IndigoReef","created_at":"2026-02-16T13:38:21.718924116Z","created_by":"ubuntu","updated_at":"2026-02-16T13:53:35.930985974Z","source_repo":".","compaction_level":0,"original_size":0,"labels":["benchmark","perf-3x","phase-1","validation"],"dependencies":[{"issue_id":"bd-3ar8v.2.8.2","depends_on_id":"bd-3ar8v.2.8","type":"parent-child","created_at":"2026-02-16T13:38:21.718924116Z","created_by":"ubuntu"}],"comments":[{"id":1836,"issue_id":"bd-3ar8v.2.8.2","author":"Dicklesworthstone","text":"Implemented validator hardening in tests/bench_schema.rs: added strict positive-finite numeric checks for matrix_cells[*].primary_e2e.{wall_clock_ms,rust_vs_node_ratio,rust_vs_bun_ratio} and primary_outcomes.{wall_clock_ms,rust_vs_node_ratio,rust_vs_bun_ratio}; added regression tests phase1_matrix_validator_rejects_non_numeric_primary_e2e_metric and phase1_matrix_validator_rejects_non_positive_primary_outcomes_ratio. cargo fmt --check passes. cargo test/check/clippy are currently running via rch with isolated CARGO_TARGET_DIR=/data/tmp/pi_agent_rust/indigoreef2 under heavy shared compile load.","created_at":"2026-02-16T13:53:35Z"}]}
 {"id":"bd-3ar8v.2.8.20","title":"[Phase 1][Support] Enforce fail-cell primary metric typing in phase1 matrix validator","description":"Tighten phase1 matrix validation so primary_e2e/primary_outcomes metrics remain numeric/positive when present even on status=fail rows; only null is allowed for missing evidence. Add malformed-payload regressions for non-numeric fail-cell metrics and fail-status primary_outcomes metrics.","status":"closed","priority":0,"issue_type":"task","assignee":"CyanHawk","created_at":"2026-02-16T18:38:03.693440448Z","created_by":"ubuntu","updated_at":"2026-02-16T18:43:26.862118960Z","closed_at":"2026-02-16T18:43:26.862094735Z","close_reason":"Completed","source_repo":".","compaction_level":0,"original_size":0,"labels":["benchmark","perf-3x","phase-1","support","validation"],"dependencies":[{"issue_id":"bd-3ar8v.2.8.20","depends_on_id":"bd-3ar8v.2.8","type":"parent-child","created_at":"2026-02-16T18:38:03.693440448Z","created_by":"ubuntu"}]}
+{"id":"bd-3ar8v.2.8.21","title":"[Phase 1][Support] Add static token guards for phase1 matrix-cell status claim emission","description":"Non-overlapping support slice under bd-3ar8v.2.8 scoped to tests/ci_full_suite_gate.rs: enforce run_all static token coverage for phase1 matrix-cell status claim emission (claim_id/metric_scope) so claim-integrity gating fails closed if script wiring regresses.","status":"closed","priority":0,"issue_type":"task","assignee":"GreenGlen","created_at":"2026-02-16T20:16:10.381276728Z","created_by":"ubuntu","updated_at":"2026-02-16T20:18:34.066662168Z","closed_at":"2026-02-16T20:18:34.066636871Z","close_reason":"Completed","source_repo":".","compaction_level":0,"original_size":0,"labels":["benchmark","perf-3x","phase-1","support","validation"],"dependencies":[{"issue_id":"bd-3ar8v.2.8.21","depends_on_id":"bd-3ar8v.2.8","type":"parent-child","created_at":"2026-02-16T20:16:10.381276728Z","created_by":"ubuntu"}]}
