 {"id":"bd-3ar8v.3.8.1.2","title":"[Phase 2][Support] Reduce perf_regression binary-size overage via release/profile/binary-surface audit","description":"Parallel non-overlapping support slice for bd-3ar8v.3.8.1: isolate immediate binary-size contributors in release build surface (Cargo/release/profile/bin shape), implement minimal-risk reductions, and report measured delta + touched files without editing existing lock-poison harness files owned by bd-3ar8v.3.8.1.1.","status":"in_progress","priority":0,"issue_type":"task","assignee":"WindyHollow","created_at":"2026-02-16T06:43:13.298468799Z","created_by":"ubuntu","updated_at":"2026-02-16T06:43:13.298468799Z","source_repo":".","compaction_level":0,"original_size":0,"labels":["budget","perf-3x","perf-regression","phase-2"],"dependencies":[{"issue_id":"bd-3ar8v.3.8.1.2","depends_on_id":"bd-3ar8v.3.8.1","type":"parent-child","created_at":"2026-02-16T06:43:13.298468799Z","created_by":"ubuntu"}]}
 {"id":"bd-3ar8v.3.8.1.3","title":"[Phase 2][Support] Harden perf test lock handling to prevent cascade failures","description":"Add poison-tolerant lock acquisition in perf test harness paths so one failing assertion does not cascade into unrelated follow-on failures. Keep primary budget failures visible while preserving remaining perf checks for diagnostic completeness.","status":"closed","priority":0,"issue_type":"task","assignee":"TopazFalcon","created_at":"2026-02-16T06:43:33.004814191Z","created_by":"ubuntu","updated_at":"2026-02-16T06:47:51.667822596Z","closed_at":"2026-02-16T06:47:51.667786559Z","close_reason":"Completed","source_repo":".","compaction_level":0,"original_size":0,"labels":["perf-3x","perf-regression","phase-2","reliability"],"dependencies":[{"issue_id":"bd-3ar8v.3.8.1.3","depends_on_id":"bd-3ar8v.3.8.1","type":"parent-child","created_at":"2026-02-16T06:43:33.004814191Z","created_by":"ubuntu"}]}
 {"id":"bd-3ar8v.3.8.1.4","title":"[Phase 2][Support] Align perf budget report artifacts with binary-size threshold and enforce consistency","description":"Non-overlapping support slice under bd-3ar8v.3.8.1: reconcile committed perf budget artifacts (tests/perf/reports/*) with current binary-size threshold policy, and add a lightweight consistency guard so report templates/artifacts do not drift from test-defined binary-size budgets.","status":"closed","priority":0,"issue_type":"task","assignee":"GentleCave","created_at":"2026-02-16T06:45:19.297296116Z","created_by":"GentleCave","updated_at":"2026-02-16T06:55:06.151545224Z","closed_at":"2026-02-16T06:55:06.151501583Z","close_reason":"Completed: added binary-size budget consistency guard + aligned budget_events artifact threshold","source_repo":".","compaction_level":0,"original_size":0,"labels":["budget","perf-3x","perf-regression","phase-2"],"dependencies":[{"issue_id":"bd-3ar8v.3.8.1.4","depends_on_id":"bd-3ar8v.3.8.1","type":"parent-child","created_at":"2026-02-16T06:45:19.297296116Z","created_by":"GentleCave"}]}
